hooks.command:
python3 -c "
import json, os, glob
ctx = []
# maintenance log — latest entry
try:
    with open('omubot/maintenance-log.md') as f:
        capture = False
        count = 0
        for line in f:
            if line.startswith('## 202'):
                if capture:
                    break
                capture = True
            if capture:
                ctx.append(line)
                count += 1
                if count > 60:
                    break
except Exception as e:
    ctx.append(f'(读取维护日志失败: {e})')
# latest bot log
try:
    logs = sorted(glob.glob('storage/logs/bot_*.log'), reverse=True)
    if logs:
        with open(logs[0]) as f:
            lines = f.readlines()
        ctx.append(f'\n--- 最新日志 ({os.path.basename(logs[0])}, 最后40行) ---\n')
        ctx.extend(lines[-40:])
    else:
        ctx.append('\n(暂无 bot 日志文件)')
except Exception as e:
    ctx.append(f'\n(读取日志失败: {e})')
# project info summary
try:
    with open('omubot/docs/project-info.md') as f:
        lines = f.readlines()
    # extract bot QQ status
    for line in lines:
        if 'Bot QQ 号' in line and '待填写' in line:
            ctx.append('\n⚠️ Bot QQ 号尚未填写，需要扫码登录后更新 omubot/docs/project-info.md')
            break
except:
    pass
if ctx:
    print(json.dumps({'hookSpecificOutput':{'hookEventName':'SessionStart','additionalContext':'项目状态快照 — 请先了解当前状态再开始工作:\n\n'+''.join(ctx)}}))
"
